import { useId, type ReactNode } from "react";

type CalloutVariant = "info" | "warning" | "error";

interface CalloutProps {
  /**
   * The title displayed at the top of the box
   */
  title?: string;

  /**
   * The description content
   */
  children: ReactNode;

  /**
   * The visual variant of the callout
   * @default 'info'
   */
  variant?: CalloutVariant;
}

const variantStyles: Record<
  CalloutVariant,
  {
    backgroundColor: string;
    borderColor: string;
    textColor: string;
    linkColor: string;
  }
> = {
  info: {
    backgroundColor: "#dbeafe",
    borderColor: "#3b82f6",
    textColor: "#1e3a5f", // Dark blue-gray for contrast on light blue bg
    linkColor: "#1e40af", // Darker blue for links
  },
  warning: {
    backgroundColor: "#fef3c7",
    borderColor: "#f59e0b",
    textColor: "#78350f", // Dark brown for contrast on light yellow bg
    linkColor: "#92400e", // Dark amber/brown for links
  },
  error: {
    backgroundColor: "#fee2e2",
    borderColor: "#ef4444",
    textColor: "#7f1d1d", // Dark red for contrast on light red bg
    linkColor: "#991b1b", // Dark red for links
  },
};

// Scoped styles for links, code, and margin normalization
const getScopedStyles = (calloutId: string, linkColor: string) => `
  .${calloutId} a {
    color: ${linkColor};
    font-weight: 600;
    text-decoration: underline;
  }
  .${calloutId} a:hover {
    text-decoration: none;
  }
  .${calloutId} code {
    background-color: rgba(0, 0, 0, 0.06);
    color: rgba(0, 0, 0, 0.85);
    padding: 2px 6px;
    border-radius: 4px;
    font-size: 0.9em;
    font-weight: 600;
  }
  .${calloutId}-content > *:first-child {
    margin-top: 0;
  }
  .${calloutId}-content > *:last-child {
    margin-bottom: 0;
  }
`;

/**
 * @internal
 * A callout box for Storybook documentation.
 * Not exported from the design system - only used in MDX docs.
 */
export function Callout({ title, children, variant = "info" }: CalloutProps) {
  const styles = variantStyles[variant];
  const calloutId = `docs-callout-${useId().replace(/:/g, "")}`;

  return (
    <>
      <style>{getScopedStyles(calloutId, styles.linkColor)}</style>
      <div
        className={calloutId}
        style={{
          padding: "16px",
          backgroundColor: styles.backgroundColor,
          borderLeft: `4px solid ${styles.borderColor}`,
          borderRadius: "4px",
          marginBottom: "24px",
          color: styles.textColor,
        }}
      >
        {title && <strong>{title}</strong>}
        <div
          className={`${calloutId}-content`}
          style={{ marginTop: title ? "8px" : 0 }}
        >
          {children}
        </div>
      </div>
    </>
  );
}
